/*
  Файл index.js является точкой входа в наше приложение
  и только он должен содержать логику инициализации нашего приложения
  используя при этом импорты из других файлов

  Из index.js не допускается что то экспортировать
*/

import {
  createCardElement,
  deleteCardElement,
  likeCard,
} from "./components/card.js";
import {
  openModalWindow,
  closeModalWindow,
  setCloseModalWindowEventListeners,
} from "./components/modal.js";
import { enableValidation, clearValidation } from "./components/validation.js";
import {
  getUserInfo,
  getCardList,
  setUserInfo,
  setUserAvatar,
  createCard,
  deleteCard,
  changeLikeCardStatus,
} from "./components/api.js";

// DOM узлы
const placesWrap = document.querySelector(".places__list");
const profileFormModalWindow = document.querySelector(".popup_type_edit");
const profileForm = profileFormModalWindow.querySelector(".popup__form");
const profileTitleInput = profileForm.querySelector(".popup__input_type_name");
const profileDescriptionInput = profileForm.querySelector(
  ".popup__input_type_description",
);

const cardFormModalWindow = document.querySelector(".popup_type_new-card");
const cardForm = cardFormModalWindow.querySelector(".popup__form");
const cardNameInput = cardForm.querySelector(".popup__input_type_card-name");
const cardLinkInput = cardForm.querySelector(".popup__input_type_url");

const cardFormRemoveModalWindow = document.querySelector(
  ".popup_type_remove-card",
);
const cardFormRemove = cardFormRemoveModalWindow.querySelector(".popup__form");

const cardInfoModalWindow = document.querySelector(".popup_type_info");
const cardInfoTitle = cardInfoModalWindow.querySelector(".popup__title");
const cardInfoText = cardInfoModalWindow.querySelector(".popup__text");
const cardInfoList = cardInfoModalWindow.querySelector(".popup__info");
const cardInfoUsersList = cardInfoModalWindow.querySelector(".popup__list");

const imageModalWindow = document.querySelector(".popup_type_image");
const imageElement = imageModalWindow.querySelector(".popup__image");
const imageCaption = imageModalWindow.querySelector(".popup__caption");

const openProfileFormButton = document.querySelector(".profile__edit-button");
const openCardFormButton = document.querySelector(".profile__add-button");

const profileTitle = document.querySelector(".profile__title");
const profileDescription = document.querySelector(".profile__description");
const profileAvatar = document.querySelector(".profile__image");

const avatarFormModalWindow = document.querySelector(".popup_type_edit-avatar");
const avatarForm = avatarFormModalWindow.querySelector(".popup__form");
const avatarInput = avatarForm.querySelector(".popup__input");

let currentUserId;

const validationSettings = {
  formSelector: ".popup__form",
  inputSelector: ".popup__input",
  submitButtonSelector: ".popup__button",
  inactiveButtonClass: "popup__button_disabled",
  inputErrorClass: "popup__input_type_error",
  errorClass: "popup__error_visible",
};

enableValidation(validationSettings);

const handlePreviewPicture = ({ name, link }) => {
  imageElement.src = link;
  imageElement.alt = name;
  imageCaption.textContent = name;
  openModalWindow(imageModalWindow);
};

const handleProfileFormSubmit = (evt) => {
  evt.preventDefault();
  const submitButton = profileFormModalWindow.querySelector(".popup__button");
  const defaultText = submitButton.textContent;
  submitButton.textContent = "Сохранение...";
  setUserInfo({
    name: profileTitleInput.value,
    about: profileDescriptionInput.value,
  })
    .then((userData) => {
      profileTitle.textContent = userData.name;
      profileDescription.textContent = userData.about;
      closeModalWindow(profileFormModalWindow);
    })
    .catch((err) => {
      console.log(err);
    })
    .finally(() => {
      submitButton.textContent = defaultText;
    });
};

const handleAvatarFromSubmit = (evt) => {
  evt.preventDefault();
  const submitButton = avatarFormModalWindow.querySelector(".popup__button");
  const defaultText = submitButton.textContent;
  submitButton.textContent = "Сохранение...";
  setUserAvatar(avatarInput.value)
    .then((userData) => {
      profileAvatar.style.backgroundImage = `url(${userData.avatar})`;
      closeModalWindow(avatarFormModalWindow);
    })
    .catch((err) => {
      console.log(err);
    })
    .finally(() => {
      submitButton.textContent = defaultText;
    });
};

const waitUserRemoveConfirmation = () => {
  return new Promise((resolve, reject) => {
    cardFormRemove.onsubmit = (evt) => {
      evt.preventDefault();
      resolve();
    };

    cardFormRemoveModalWindow.querySelector(".popup__close").onclick = () => {
      reject(new Error("cancelled"));
    };
  });
};

const handleCardDelete = (cardElement, id) => {
  openModalWindow(cardFormRemoveModalWindow);
  const submitButton =
    cardFormRemoveModalWindow.querySelector(".popup__button");
  const defaultText = submitButton.textContent;
  return waitUserRemoveConfirmation()
    .then(() => {
      submitButton.textContent = "Удаление...";
      return deleteCard(id);
    })
    .then(() => {
      deleteCardElement(cardElement);
      closeModalWindow(cardFormRemoveModalWindow);
    })
    .catch((err) => {
      if (err.message !== "cancelled") {
        console.log(err);
      }
    })
    .finally(() => {
      submitButton.textContent = defaultText;
    });
};

const handleLikeCard = (likeButton, likesCount, data, userId) => {
  const isLiked = data.likes.some((user) => user._id === userId);
  changeLikeCardStatus(data._id, isLiked)
    .then((updatedCardData) => {
      data.likes = updatedCardData.likes;
      likeCard(
        likeButton,
        likesCount,
        updatedCardData.likes,
        updatedCardData.likes.some((user) => user._id === userId),
      );
    })
    .catch((err) => {
      console.log(err);
    });
};

const formatDate = (date) =>
  date.toLocaleDateString("ru-RU", {
    year: "numeric",
    month: "long",
    day: "numeric",
  });

const getInfoDefinitionTemplate = () => {
  return document
    .getElementById("popup-info-definition-template")
    .content.querySelector(".popup__info-item")
    .cloneNode(true);
};

const getUserInfoPreviewTemplate = () => {
  return document
    .getElementById("popup-info-user-preview-template")
    .content.querySelector(".popup__list-item")
    .cloneNode(true);
};

const handleInfoClick = (cardId) => {
  getCardList()
    .then((cards) => {
      const card = cards.find((card) => card._id === cardId);
      cardInfoTitle.textContent = "Информация о карточке";
      cardInfoList.innerHTML = "";
      cardInfoUsersList.innerHTML = "";

      const items = [
        { term: "Описание", description: card.name },
        {
          term: "Дата создания",
          description: formatDate(new Date(card.createdAt)),
        },
        { term: "Владелец", description: card.owner.name },
        { term: "Количество лайков", description: card.likes.length },
      ];

      items.forEach(({ term, description }) => {
        const currentItem = getInfoDefinitionTemplate();
        currentItem.querySelector(".popup__info-term").textContent = term;
        currentItem.querySelector(".popup__info-description").textContent =
          description;
        cardInfoList.append(currentItem);
      });

      cardInfoText.textContent = "Лайкнули:";
      card.likes.forEach((user) => {
        const userItem = getUserInfoPreviewTemplate();
        userItem.textContent = user.name;
        cardInfoUsersList.append(userItem);
      });
      openModalWindow(cardInfoModalWindow);
    })
    .catch((err) => {
      console.log(err);
    });
};

const handleCardFormSubmit = (evt) => {
  evt.preventDefault();
  const submitButton = cardFormModalWindow.querySelector(".popup__button");
  const defaultText = submitButton.textContent;
  submitButton.textContent = "Создание...";
  createCard({
    name: cardNameInput.value,
    link: cardLinkInput.value,
  })
    .then((cardData) => {
      placesWrap.prepend(
        createCardElement(cardData, currentUserId, {
          onPreviewPicture: handlePreviewPicture,
          onLikeIcon: (likeButton, likesCount, data) =>
            handleLikeCard(likeButton, likesCount, data, currentUserId),
          onDeleteCard: handleCardDelete,
          onInfoIcon: handleInfoClick,
        }),
      );
      closeModalWindow(cardFormModalWindow);
    })
    .catch((err) => {
      console.log(err);
    })
    .finally(() => {
      submitButton.textContent = defaultText;
    });
};

// EventListeners
profileForm.addEventListener("submit", handleProfileFormSubmit);
cardForm.addEventListener("submit", handleCardFormSubmit);
avatarForm.addEventListener("submit", handleAvatarFromSubmit);

openProfileFormButton.addEventListener("click", () => {
  profileTitleInput.value = profileTitle.textContent;
  profileDescriptionInput.value = profileDescription.textContent;
  clearValidation(profileForm, validationSettings);
  openModalWindow(profileFormModalWindow);
});

profileAvatar.addEventListener("click", () => {
  avatarForm.reset();
  clearValidation(avatarForm, validationSettings);
  openModalWindow(avatarFormModalWindow);
});

openCardFormButton.addEventListener("click", () => {
  cardForm.reset();
  clearValidation(cardForm, validationSettings);
  openModalWindow(cardFormModalWindow);
});

//настраиваем обработчики закрытия попапов
const allPopups = document.querySelectorAll(".popup");
allPopups.forEach((popup) => {
  setCloseModalWindowEventListeners(popup);
});

Promise.all([getCardList(), getUserInfo()])
  .then(([cards, userData]) => {
    currentUserId = userData._id;
    cards.forEach((cardData) => {
      const cardElement = createCardElement(cardData, currentUserId, {
        onPreviewPicture: handlePreviewPicture,
        onLikeIcon: (likeButton, likesCount, data) =>
          handleLikeCard(likeButton, likesCount, data, currentUserId),
        onDeleteCard: handleCardDelete,
        onInfoIcon: handleInfoClick,
      });
      placesWrap.append(cardElement);
    });
    profileTitle.textContent = userData.name;
    profileDescription.textContent = userData.about;
    profileAvatar.style.backgroundImage = `url('${userData.avatar}')`;
  })
  .catch((err) => {
    console.log(err);
  });
