export const likeCard = (likeButton, likesCount, likes, isLiked) => {
  likeButton.classList.toggle("card__like-button_is-active", isLiked);
  likesCount.textContent = likes.length;
};

export const deleteCardElement = (cardElement) => {
  cardElement.remove();
};

const getTemplate = () => {
  return document
    .getElementById("card-template")
    .content.querySelector(".card")
    .cloneNode(true);
};

export const createCardElement = (
  data,
  currentUserId,
  { onPreviewPicture, onLikeIcon, onDeleteCard, onInfoIcon },
) => {
  const cardElement = getTemplate();
  const likeButton = cardElement.querySelector(".card__like-button");
  const likesCount = cardElement.querySelector(".card__like-count");
  const deleteButton = cardElement.querySelector(
    ".card__control-button_type_delete",
  );
  const infoButton = cardElement.querySelector(
    ".card__control-button_type_info",
  );
  const cardImage = cardElement.querySelector(".card__image");
  const cardTitle = cardElement.querySelector(".card__title");

  cardImage.src = data.link;
  cardImage.alt = data.name;
  cardTitle.textContent = data.name;
  likesCount.textContent = data.likes.length;

  likeCard(
    cardElement.querySelector(".card__like-button"),
    cardElement.querySelector(".card__like-count"),
    data.likes,
    data.likes.some((user) => user._id === currentUserId),
  );

  if (onLikeIcon) {
    likeButton.addEventListener("click", () => {
      onLikeIcon(likeButton, likesCount, data);
    });
  }

  if (onDeleteCard) {
    deleteButton.addEventListener("click", () => {
      onDeleteCard(cardElement, data._id);
    });
  }

  if (onInfoIcon) {
    infoButton.addEventListener("click", () => {
      onInfoIcon(data._id);
    });
  }

  if (onPreviewPicture) {
    cardImage.addEventListener("click", () => {
      onPreviewPicture({ name: data.name, link: data.link });
    });
  }

  if (data.owner._id !== currentUserId) {
    deleteButton.remove();
  }

  return cardElement;
};
